function getT(lang) {
  const l = lang ?? "en";
  const dict = l === "en" ? EN : KO;
  return (key) => dict[key] ?? KO[key];
}
function jsonLangInstr(lang) {
  return lang === "en" ? "All output in English. Return JSON only (no code blocks)." : "\uBAA8\uB450 \uD55C\uAD6D\uC5B4. JSON\uB9CC \uBC18\uD658(\uCF54\uB4DC\uBE14\uB85D \uC5C6\uC774).";
}

