async function summarizeFolder(nodes, settings, mode = "summary", intent) {
  if (nodes.length === 0)
    return { synthesis: "", overview: "", themes: [], highlights: [], link_contexts: [] };
  const digest = nodes.map((n) => {
    const edgePart = n.edges.length > 0 ? "\n\uC5F0\uACB0: " + n.edges.slice(0, 3).map((e) => `[${e.relation}]\u2192${e.target}`).join(", ") : "";
    return `### ${n.title} [${n.nodeType}]
${n.content.slice(0, 250)}${edgePart}`;
  }).join("\n\n");
  return summarizeSubgraph(digest, settings, mode, intent);
}
